B.Xl=new A.l(2001,5,19,"\uccab \ub9e4\uc7a5","\uc560\ud50c, \uccab \uc624\ud504\ub77c\uc778 \ub9e4\uc7a5 \uc5f4\ub2e4","\uc560\ud50c\uc774 \ubbf8\uad6d\uc5d0 \uc9c1\uc601 \ub9e4\uc7a5 1\ud638\uc810\uc744 \uc5f4\uc5c8\ub2e4. \uc81c\ud488\uc744 \uc9c1\uc811 \ub9cc\uc9c0\uac8c \ud558\ub294 \uc0c8 \uc720\ud1b5 \uc2e4\ud5d8\uc774 \uc2dc\uc791\ub410\ub2e4.","\uc9c1\uc811 \ubcf4\uc5ec\uc8fc\ub294 \uc720\ud1b5, \ucc98\uc74c\uc5d4 \ubb34\ubaa8\ud574 \ubcf4\uc600\uc2b5\ub2c8\ub2e4.",B.w)
