B.Zd=new A.l(2001,6,25,"\ud1b5\uc2e0 \ud569\ubcd1","SK\ud154\ub808\ucf64\xb7\uc2e0\uc138\uae30\ud1b5\uc2e0 \ud569\ubcd1 \ud569\uc758","1\uc704 \uc774\ub3d9\ud1b5\uc2e0\uc0ac\uac00 \uc2e0\uc138\uae30\ud1b5\uc2e0 \ud569\ubcd1\uc5d0 \ucd5c\uc885 \ud569\uc758\ud588\ub2e4. \ud1b5\uc2e0 \uc2dc\uc7a5\uc774 \uc7ac\ud3b8\ub41c\ub2e4.","\ud569\ubcd1\uc740 \ubab8\uc9d1\uc744 \ud0a4\uc6b0\uc9c0\ub9cc \uaddc\uc81c\uc758 \ub208\ucd1d\ub3c4 \ubc1b\uc2b5\ub2c8\ub2e4.",B.q)
B.Z7=new A.l(2001,6,28,"\ubc18\ub3c5\uc810","\ud56d\uc18c\ubc95\uc6d0, MS \uac15\uc81c\ubd84\ud560 \uba85\ub839 \ub4a4\uc9d1\ub2e4","\ubc95\uc6d0\uc774 \ub9c8\uc774\ud06c\ub85c\uc18c\ud504\ud2b8 \ubd84\ud560 \uba85\ub839\uc744 \ud30c\uae30\ud588\ub2e4. \ub2e4\ub9cc \ub3c5\uc810 \uc0ac\uc2e4\uc740 \uadf8\ub300\ub85c \uc778\uc815\ub410\ub2e4.","\uaddc\uc81c \ub9ac\uc2a4\ud06c\uac00 \uac77\ud788\uba74 \uc8fc\uac00\ub294 \uc548\ub3c4\ud569\ub2c8\ub2e4.",B.q)
B.Uv=new A.l(2001,7,9,"\ub2f7\ucef4 \ub3c4\uc0b0","\uc628\ub77c\uc778 \uc2dd\ub8cc\ud488 \uc6f9\ubc34, \ud30c\uc0b0 \uc2e0\uccad","\uc218\uc5b5 \ub2ec\ub7ec\ub97c \ud0dc\uc6b4 \ub300\ud45c \ub2f7\ucef4 \uae30\uc5c5\uc774 \ubb38\uc744 \ub2eb\uc558\ub2e4. \uc778\ud130\ub137 \uac70\ud488 \ubd95\uad34\uc758 \uc0c1\uc9d5\uc774 \ub410\ub2e4.","\uc131\uc7a5 \uc2a4\ud1a0\ub9ac\ub9cc\uc73c\ub85c\ub294 \uccad\uad6c\uc11c\ub97c \ub9c9\uc9c0 \ubabb\ud569\ub2c8\ub2e4.",B.r)
B.a_h=new A.l(2001,7,11,"\uc11c\ube44\uc2a4 \uc911\ub2e8","\ub0c5\uc2a4\ud130, \ubc95\uc6d0 \uba85\ub839\uc5d0 \uc11c\ube44\uc2a4 \uc911\ub2e8","\uc74c\uc545 \uacf5\uc720 \uc5f4\ud48d\uc744 \uc77c\uc73c\ud0a8 \ub0c5\uc2a4\ud130\uac00 \uacb0\uad6d \uba48\ucdb0 \uc130\ub2e4. \ub514\uc9c0\ud138 \uc74c\uc545\uc758 \uaddc\uce59\uc774 \ub2e4\uc2dc \uc9dc\uc778\ub2e4.","\ud601\uc2e0\uc774 \ubc95\uc744 \uc55e\uc11c\uac00\uba74 \uc81c\ub3d9\uc774 \uac78\ub9ac\uae30\ub3c4 \ud569\ub2c8\ub2e4.",B.r)
B.XZ=new A.l(2001,7,13,"\uc62c\ub9bc\ud53d \uc720\uce58","2008 \uc62c\ub9bc\ud53d \uac1c\ucd5c\uc9c0, \ubca0\uc774\uc9d5 \uc120\uc815","\uad6d\uc81c\uc62c\ub9bc\ud53d\uc704\uc6d0\ud68c\uac00 2008\ub144 \uc5ec\ub984 \uc62c\ub9bc\ud53d\uc744 \ubca0\uc774\uc9d5\uc5d0 \ub9e1\uacbc\ub2e4. \uc911\uad6d\uc758 \ubd80\uc0c1\uc774 \uc0c1\uc9d5\uc801\uc73c\ub85c \ud655\uc778\ub410\ub2e4.","\ub300\ud615 \uc774\ubca4\ud2b8\ub294 \uba87 \ub144\uce58 \ud22c\uc790 \ud14c\ub9c8\ub97c \ub9cc\ub4ed\ub2c8\ub2e4.",B.q)
