B.a_9=new A.l(2001,7,19,"\uc0ac\uc774\ubc84 \uc704\ud611","'\ucf54\ub4dc\ub808\ub4dc' \uc6dc, \ud558\ub8e8 \ub9cc\uc5d0 35\ub9cc \ub300 \uac10\uc5fc","\uc778\ud130\ub137 \uc6dc\uc774 \ube60\ub974\uac8c \ud37c\uc838 \uc11c\ubc84 \uc218\uc2ed\ub9cc \ub300\ub97c \ub36e\ucce4\ub2e4. \uc5f0\uacb0\ub41c \uc138\uc0c1\uc758 \ucde8\uc57d\ud568\uc774 \ub4dc\ub7ec\ub0ac\ub2e4.","\ub514\uc9c0\ud138 \uc778\ud504\ub77c\ub3c4 \uc0ac\uace0 \uc704\ud5d8\uc744 \ud488\uace0 \uc788\uc2b5\ub2c8\ub2e4.",B.r)
B.Z1=new A.l(2001,8,4,"\ubd81\ub7ec \uc815\uc0c1","\uae40\uc815\uc77c\xb7\ud478\ud2f4, \ubaa8\uc2a4\ud06c\ubc14 \uc815\uc0c1\ud68c\ub2f4","\ubd81\ud55c \uc9c0\ub3c4\uc790\uac00 \ub7ec\uc2dc\uc544\ub97c \ucc3e\uc544 \uc815\uc0c1\ud68c\ub2f4\uc744 \ud588\ub2e4. \ud55c\ubc18\ub3c4 \uc8fc\ubcc0 \uc678\uad50\uac00 \ubd84\uc8fc\ud558\ub2e4.","\ud55c\ubc18\ub3c4 \ub274\uc2a4\ub294 \uc5b8\uc81c\ub098 \uc2dc\uc7a5\uc758 \ubc30\uacbd \ubcc0\uc218\uc785\ub2c8\ub2e4.",B.I)
B.Zn=new A.l(2001,8,13,"\ud55c\uc77c \uac08\ub4f1","\uace0\uc774\uc988\ubbf8, \uc57c\uc2a4\ucfe0\ub2c8 \uc2e0\uc0ac \ucc38\ubc30","\uc77c\ubcf8 \ucd1d\ub9ac\uac00 \uc804\ubc94\uc774 \ud569\uc0ac\ub41c \uc2e0\uc0ac\ub97c \ucc38\ubc30\ud588\ub2e4. \ud55c\uad6d\uacfc \uc911\uad6d\uc774 \uac15\ud558\uac8c \ubc18\ubc1c\ud588\ub2e4.","\uc678\uad50 \ub9c8\ucc30\uc740 \uad50\uc5ed\xb7\uad00\uad11\xb7\uc5ec\ub860\uc5d0 \uc2a4\uba70\ub4ed\ub2c8\ub2e4.",B.r)
B.VV=new A.l(2001,8,23,"IMF \uc878\uc5c5","\ud55c\uad6d, IMF \uad6c\uc81c\uae08\uc735 \uc870\uae30 \uc0c1\ud658 \uc644\ub8cc","\uc678\ud658\uc704\uae30 \ub54c \ube4c\ub9b0 \ub3c8\uc744 \uc608\uc815\ubcf4\ub2e4 \uc55e\ub2f9\uaca8 \ubaa8\ub450 \uac1a\uc558\ub2e4. '\uc544\uc774\uc5e0\uc5d0\ud504 \uc2dc\ub300'\uac00 \uacf5\uc2dd\uc801\uc73c\ub85c \ub05d\ub0ac\ub2e4.","\ube5a\uc744 \uac1a\ub294 \uc21c\uac04 \uc9c4\uc9dc \ud68c\ubcf5\uc774 \uc2dc\uc791\ub429\ub2c8\ub2e4.",B.q)
B.Vs=new A.l(2001,8,24,"\uac1c\ubc1c \uc644\ub8cc","\ub9c8\uc774\ud06c\ub85c\uc18c\ud504\ud2b8, \uc708\ub3c4\uc6b0 XP \uac1c\ubc1c \uc644\ub8cc","\uc708\ub3c4\uc6b0 XP\uac00 \uc81c\uc870\uc0ac\uc5d0 \ubc30\ud3ec\ub418\uba70 \ucd9c\uc2dc \uc900\ube44\ub97c \ub9c8\ucce4\ub2e4. \uc0c8 PC \ud45c\uc900\uc758 \ub4f1\uc7a5\uc774 \ucd08\uc77d\uae30\uc5d0 \ub4e4\uc5b4\uac14\ub2e4.","\uc81c\ud488\uc774 \uc644\uc131\ub418\uba74 \ub2e4\uc74c \uad00\ubb38\uc740 \uc2dc\uc7a5\uc758 \ubc18\uc751\uc785\ub2c8\ub2e4.",B.q)
