B.Wq=new A.l(2001,9,11,"\ud14c\ub7ec","9\xb711 \ud14c\ub7ec, \ub274\uc695\xb7\uc6cc\uc2f1\ud134 \ud53c\uaca9","\uc5ec\uac1d\uae30 \ub124 \ub300\uac00 \ub0a9\uce58\ub3fc \uc138\uacc4\ubb34\uc5ed\uc13c\ud130\uc640 \uad6d\ubc29\ubd80 \ub4f1\uc744 \uac15\ud0c0\ud588\uace0 \uc57d 3\ucc9c \uba85\uc774 \uc228\uc84c\ub2e4. \uc138\uacc4\uac00 \uba48\ucdb0 \uc130\ub2e4.","\uc0ac\uc2e4\ub9cc \ub2f4\ub2f4\ud788 \uc804\ud569\ub2c8\ub2e4. \uc2dc\uc7a5\uc740 \ud55c\ub3d9\uc548 \uacf5\ud3ec\uc5d0 \uc9c0\ubc30\ub429\ub2c8\ub2e4.",B.r)
B.Vb=new A.l(2001,9,14,"\ucf58\uc194 \ucd9c\uc2dc","\ub2cc\ud150\ub3c4 \uac8c\uc784\ud050\ube0c, \uc77c\ubcf8 \ubc1c\ub9e4","\ub2cc\ud150\ub3c4\uc758 \uc0c8 \uac70\uce58\ud615 \uac8c\uc784\uae30\uac00 \uc77c\ubcf8\uc5d0\uc11c \ucd9c\uc2dc\ub410\ub2e4. \uc18c\ub2c8\xb7MS\uc640\uc758 \ucf58\uc194 3\ud30c\uc804\uc774 \ub2ec\uc544\uc624\ub978\ub2e4.","3\ud30c\uc804\uc758 \uc2b9\uc790\ub294 \uae30\uae30 \uc131\ub2a5\ub9cc\uc73c\ub85c \uac08\ub9ac\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4.",B.w)
B.W5=new A.l(2001,9,17,"\uc99d\uc2dc \uc7ac\uac1c\uc7a5","9\xb711 \ub2f7\uc0c8 \ub9cc\uc5d0 \ub274\uc695\uc99d\uc2dc \uc7ac\uac1c\uc7a5, \uae09\ub77d","\ub098\ud758\uac04 \uba48\ucdc4\ub358 \uc99d\uc2dc\uac00 \ub2e4\uc2dc \uc5f4\ub9ac\uc790 \uc8fc\uac00\uac00 \ud06c\uac8c \ub5a8\uc5b4\uc84c\ub2e4. \uacf5\ud3ec\uac00 \uc2dc\uc7a5\uc744 \uc9d3\ub20c\ub800\ub2e4.","\ud328\ub2c9\uc758 \ud55c\ubcf5\ud310\uc5d0\uc11c \uc6d0\uce59\uc744 \uc9c0\ud0a4\uae30\uac00 \uac00\uc7a5 \uc5b4\ub835\uc2b5\ub2c8\ub2e4.",B.r)
B.Yk=new A.l(2001,9,21,"\ub9e4\uac01 \ud569\uc758","\ub300\uc6b0\uc790\ub3d9\ucc28, GM\uc5d0 \ub9e4\uac01 \uc591\ud574\uac01\uc11c","\ubd80\ub3c4\ub09c \ub300\uc6b0\uc790\ub3d9\ucc28\uac00 \ubbf8\uad6d GM\uc5d0 \ud314\ub9ac\ub294 \uc808\ucc28\ub97c \uc2dc\uc791\ud588\ub2e4. \uc7ac\ubc8c \uad6c\uc870\uc870\uc815\uc758 \ud55c \ub9e4\ub4ed\uc774 \uc9c0\uc5b4\uc84c\ub2e4.","\uc704\uae30 \uae30\uc5c5\uc758 \uc8fc\uc778\uc774 \ubc14\ub00c\uba74 \ud310\uc774 \ub9ac\uc14b\ub429\ub2c8\ub2e4.",B.q)
B.Yc=new A.l(2001,10,1,"\ud569\uc791 \ucd9c\ubc94","\uc18c\ub2c8-\uc5d0\ub9ad\uc2a8 \ud734\ub300\ud3f0 \ud569\uc791\uc0ac \ucd9c\ubc94","\uc18c\ub2c8\uc640 \uc5d0\ub9ad\uc2a8\uc774 \uc808\ubc18\uc529 \ud22c\uc790\ud55c \ud734\ub300\ud3f0 \ud68c\uc0ac\uac00 \uc601\uc5c5\uc744 \uc2dc\uc791\ud588\ub2e4. \ubaa8\ubc14\uc77c \uacbd\uc7c1\uc5d0 \uc0c8 \uc120\uc218\uac00 \ub4f1\uc7a5\ud588\ub2e4.","\ub3d9\ub9f9\uc73c\ub85c \uc57d\uc810\uc744 \uba54\uc6b0\ub294 \uc804\ub7b5, \uc131\ud328\ub294 \uc2e4\ud589\uc5d0 \ub2ec\ub838\uc2b5\ub2c8\ub2e4.",B.w)
B.Zy=new A.l(2001,10,4,"\uc5ec\uac1d\uae30 \ucc38\uc0ac","\uc2dc\ubca0\ub9ac\uc544\ud56d\uacf5 \uc5ec\uac1d\uae30, \ud751\ud574\uc11c \ucd94\ub77d","\ud6c8\ub828 \uc911\uc774\ub358 \ubbf8\uc0ac\uc77c\uc5d0 \ub9de\uc544 \uc5ec\uac1d\uae30\uac00 \ucd94\ub77d\ud574 \uc2b9\uac1d\uacfc \uc2b9\ubb34\uc6d0 78\uba85\uc774 \uc228\uc84c\ub2e4.","\uc0ac\uc2e4\ub9cc \ub2f4\ub2f4\ud788 \uc804\ud569\ub2c8\ub2e4.",B.r)
