B.Vt=new A.l(2001,10,23,"\uc81c\ud488 \uacf5\uac1c","\uc560\ud50c, \uc544\uc774\ud31f \uacf5\uac1c","'\uc8fc\uba38\ub2c8 \uc18d \ucc9c \uace1'\uc744 \ub0b4\uac74 \uc18c\ud615 MP3 \ud50c\ub808\uc774\uc5b4\uac00 \ub4f1\uc7a5\ud588\ub2e4. \uc560\ud50c\uc774 \uc74c\uc545 \uae30\uae30\ub85c \uc601\uc5ed\uc744 \ub113\ud614\ub2e4.","\uc7a5\uae30 \ubcf5\ub9ac\uc640 \ub2e8\uae30 \uc0dd\uc874\uc758 \uade0\ud615\uc744 \uc0dd\uac01\ud558\uc138\uc694.",B.w)
